// Tax4Us Orchestration Agent - Agent Registry
const agentRegistry = {
  agents: {
    content_intelligence: {
      name: "Content Intelligence Agent",
      status: "active",
      capabilities: ["content_research", "trend_analysis", "keyword_research"],
      webhook: "https://tax4usllc.app.n8n.cloud/webhook/9c054bb1-4446-4502-be98-ffd3c8ca1f2d",
      input_format: {"keyword": "string", "topic": "string"},
      output_format: {"content_ideas": "array", "research_data": "object"}
    },
    blog_writing: {
      name: "SMART AI Blog Writing System",
      status: "active",
      capabilities: ["blog_generation", "seo_optimization", "wordpress_publishing"],
      webhook: "https://tax4usllc.app.n8n.cloud/webhook/9c054bb1-4446-4502-be98-ffd3c8ca1f2d",
      input_format: {"title": "string", "keywords": "array"},
      output_format: {"blog_post": "string", "meta_description": "string"}
    },
    podcast_agent: {
      name: "Tax4Us Podcast Agent",
      status: "created",
      capabilities: ["episode_planning", "script_generation", "captivate_integration"],
      webhook: "https://tax4usllc.app.n8n.cloud/webhook/podcast-agent",
      input_format: {"title": "string", "topic": "string"},
      output_format: {"script": "string", "description": "string", "artwork_prompt": "string"}
    },
    social_media: {
      name: "Tax4Us Social Media Agent",
      status: "created",
      capabilities: ["facebook_content", "linkedin_content", "image_prompts"],
      webhook: "https://tax4usllc.app.n8n.cloud/webhook/social-media-agent",
      input_format: {"title": "string", "platforms": "array"},
      output_format: {"facebook_post": "string", "linkedin_post": "string", "image_prompt": "string"}
    },
    blog_posts: {
      name: "Blog & Posts Agent",
      status: "archived",
      capabilities: ["blog_creation", "wordpress_publishing", "seo_optimization"],
      webhook: "https://tax4usllc.app.n8n.cloud/webhook/blog-posts-agent",
      input_format: {"title": "string", "content": "string"},
      output_format: {"wordpress_post": "object", "seo_analysis": "object"}
    }
  },
  system_status: "operational",
  total_agents: 5,
  active_agents: 2,
  created_agents: 2,
  archived_agents: 1
};

return {
  json: {
    ...agentRegistry,
    timestamp: new Date().toISOString(),
    message: "Agent registry loaded successfully"
  }
};

// Tax4Us Orchestration Agent - Request Analysis
const customerRequest = $input.first().json;
const agentRegistry = $('Agent Registry').first().json;

console.log("Tax4Us Orchestration Agent - Request Analysis");
console.log("Customer Request:", customerRequest);

// Analyze customer request and determine required services
const requestAnalysis = {
  request_id: customerRequest.request_id || `req_${Date.now()}`,
  customer_id: customerRequest.customer_id || "tax4us_customer",
  request_type: customerRequest.request_type || "content_creation",
  priority: customerRequest.priority || "medium",
  deadline: customerRequest.deadline || null,

  // Analyze content specifications
  content_spec: customerRequest.content_spec || {},
  title: customerRequest.content_spec?.title || customerRequest.title || "Tax Planning Content",
  keywords: customerRequest.content_spec?.keywords || customerRequest.keywords || ["tax planning", "israel"],
  target_audience: customerRequest.content_spec?.target_audience || customerRequest.target_audience || "Israeli business owners",

  // Determine required services
  required_services: [],
  required_agents: [],
  workflow_sequence: [],

  // Request classification
  classification: {
    content_type: "mixed",
    complexity: "medium",
    estimated_duration: "2-4 hours",
    agent_count: 0
  },

  timestamp: new Date().toISOString(),
  status: "request_analyzed"
};

// Determine required services based on request
if (customerRequest.services) {
  requestAnalysis.required_services = customerRequest.services;
} else {
  // Auto-detect services based on content spec
  if (customerRequest.content_spec?.platforms?.includes("wordpress") || customerRequest.content_spec?.platforms?.includes("blog")) {
    requestAnalysis.required_services.push("blog");
  }
  if (customerRequest.content_spec?.platforms?.includes("facebook") || customerRequest.content_spec?.platforms?.includes("linkedin")) {
    requestAnalysis.required_services.push("social_media");
  }
  if (customerRequest.content_spec?.platforms?.includes("podcast") || customerRequest.content_spec?.platforms?.includes("audio")) {
    requestAnalysis.required_services.push("podcast");
  }
  if (requestAnalysis.required_services.length === 0) {
    requestAnalysis.required_services = ["blog", "social_media"]; // Default services
  }
}

// Map services to agents
const serviceToAgentMap = {
  "blog": "blog_writing",
  "social_media": "social_media",
  "podcast": "podcast_agent",
  "content_research": "content_intelligence",
  "blog_posts": "blog_posts"
};

requestAnalysis.required_agents = requestAnalysis.required_services.map(service => serviceToAgentMap[service]).filter(Boolean);
requestAnalysis.classification.agent_count = requestAnalysis.required_agents.length;

// Determine workflow sequence
requestAnalysis.workflow_sequence = [
  "content_intelligence", // Always start with research
  ...requestAnalysis.required_agents.filter(agent => agent !== "content_intelligence")
];

console.log(`Required Services: ${requestAnalysis.required_services.join(", ")}`);
console.log(`Required Agents: ${requestAnalysis.required_agents.join(", ")}`);
console.log(`Workflow Sequence: ${requestAnalysis.workflow_sequence.join(" → ")}`);

return {
  json: {
    ...requestAnalysis,
    message: "Request analyzed and workflow planned",
    nextStep: "agent_coordination"
  }
};

// Tax4Us Orchestration Agent - Agent Coordination
const requestAnalysis = $input.first().json;
const aiRouting = $('AI Routing Analysis').first().json;
const agentRegistry = $('Agent Registry').first().json;

console.log("Tax4Us Orchestration Agent - Agent Coordination");

// Prepare coordination plan
const coordinationPlan = {
  request_id: requestAnalysis.request_id,
  customer_id: requestAnalysis.customer_id,

  // Workflow execution plan
  execution_plan: {
    sequence: requestAnalysis.workflow_sequence,
    current_step: 0,
    total_steps: requestAnalysis.workflow_sequence.length,
    status: "coordinating",

    // Agent execution details
    agents: {},
    results: {},
    errors: {},

    // Progress tracking
    progress: {
      completed: 0,
      in_progress: 0,
      pending: requestAnalysis.workflow_sequence.length,
      failed: 0
    }
  },

  // AI routing insights
  ai_insights: aiRouting.text,

  // Customer communication
  customer_updates: [
    {
      timestamp: new Date().toISOString(),
      message: `Request received and analyzed. ${requestAnalysis.required_agents.length} agents will be coordinated to fulfill your request.`,
      status: "processing"
    }
  ],

  timestamp: new Date().toISOString(),
  status: "coordinating"
};

// Initialize agent execution details
requestAnalysis.workflow_sequence.forEach((agentId, index) => {
  const agent = agentRegistry.agents[agentId];
  coordinationPlan.execution_plan.agents[agentId] = {
    name: agent.name,
    status: index === 0 ? "ready" : "pending",
    webhook: agent.webhook,
    input_data: null,
    output_data: null,
    start_time: null,
    end_time: null,
    error: null
  };
});

console.log(`Coordination plan created for ${requestAnalysis.workflow_sequence.length} agents`);
console.log(`Execution sequence: ${requestAnalysis.workflow_sequence.join(" → ")}`);

return {
  json: {
    ...coordinationPlan,
    message: "Agent coordination plan prepared",
    nextStep: "execute_workflow"
  }
};

// Tax4Us Orchestration Agent - Workflow Execution
const coordinationPlan = $input.first().json;
const requestAnalysis = $('Request Analysis').first().json;

console.log("Tax4Us Orchestration Agent - Workflow Execution");

// Prepare execution data for the first agent
const firstAgentId = coordinationPlan.execution_plan.sequence[0];
const firstAgent = coordinationPlan.execution_plan.agents[firstAgentId];

// Prepare input data for the first agent
const agentInputData = {
  // Common data for all agents
  request_id: coordinationPlan.request_id,
  customer_id: coordinationPlan.customer_id,

  // Content specifications
  title: requestAnalysis.title,
  keywords: requestAnalysis.keywords,
  target_audience: requestAnalysis.target_audience,

  // Agent-specific data
  source: "orchestration_agent",
  priority: requestAnalysis.priority,
  deadline: requestAnalysis.deadline,

  // For content intelligence agent
  Keyword: requestAnalysis.keywords.join(", "),
  Topic: requestAnalysis.title,

  // For other agents
  topic: requestAnalysis.title,
  contentType: "mixed",
  platforms: requestAnalysis.content_spec?.platforms || ["wordpress", "facebook", "linkedin"]
};

// Update coordination plan
coordinationPlan.execution_plan.agents[firstAgentId].status = "executing";
coordinationPlan.execution_plan.agents[firstAgentId].input_data = agentInputData;
coordinationPlan.execution_plan.agents[firstAgentId].start_time = new Date().toISOString();
coordinationPlan.execution_plan.current_step = 0;
coordinationPlan.execution_plan.progress.in_progress = 1;
coordinationPlan.execution_plan.progress.pending = coordinationPlan.execution_plan.total_steps - 1;

// Add customer update
coordinationPlan.customer_updates.push({
  timestamp: new Date().toISOString(),
  message: `Starting execution with ${firstAgent.name}. Progress: 0/${coordinationPlan.execution_plan.total_steps} steps completed.`,
  status: "executing"
});

console.log(`Executing ${firstAgent.name} with input:`, agentInputData);

return {
  json: {
    coordination_plan: coordinationPlan,
    agent_input: agentInputData,
    target_agent: firstAgentId,
    agent_webhook: firstAgent.webhook,
    message: "Workflow execution started",
    nextStep: "agent_execution"
  }
};

// Tax4Us Orchestration Agent - Status Tracking
const agentResponse = $input.first().json;
const executionData = $('Workflow Execution').first().json;
const coordinationPlan = executionData.coordination_plan;
const targetAgent = executionData.target_agent;

console.log("Tax4Us Orchestration Agent - Status Tracking");
console.log(`Agent ${targetAgent} execution completed:`, agentResponse);

// Update coordination plan with agent results
coordinationPlan.execution_plan.agents[targetAgent].status = "completed";
coordinationPlan.execution_plan.agents[targetAgent].output_data = agentResponse;
coordinationPlan.execution_plan.agents[targetAgent].end_time = new Date().toISOString();
coordinationPlan.execution_plan.progress.completed += 1;
coordinationPlan.execution_plan.progress.in_progress -= 1;
coordinationPlan.execution_plan.current_step += 1;

// Store results
coordinationPlan.execution_plan.results[targetAgent] = {
  success: true,
  data: agentResponse,
  execution_time: new Date().toISOString()
};

// Check if workflow is complete
const isComplete = coordinationPlan.execution_plan.progress.completed === coordinationPlan.execution_plan.total_steps;

if (isComplete) {
  coordinationPlan.status = "completed";
  coordinationPlan.execution_plan.status = "completed";

  // Add completion update
  coordinationPlan.customer_updates.push({
    timestamp: new Date().toISOString(),
    message: `All agents completed successfully! Your content is ready. Total execution time: ${coordinationPlan.execution_plan.total_steps} steps.`,
    status: "completed"
  });
} else {
  // Add progress update
  coordinationPlan.customer_updates.push({
    timestamp: new Date().toISOString(),
    message: `${coordinationPlan.execution_plan.agents[targetAgent].name} completed. Progress: ${coordinationPlan.execution_plan.progress.completed}/${coordinationPlan.execution_plan.total_steps} steps.`,
    status: "in_progress"
  });
}

console.log(`Progress: ${coordinationPlan.execution_plan.progress.completed}/${coordinationPlan.execution_plan.total_steps} completed`);
console.log(`Status: ${coordinationPlan.status}`);

return {
  json: {
    coordination_plan: coordinationPlan,
    is_complete: isComplete,
    message: isComplete ? "Workflow completed successfully" : "Workflow in progress",
    nextStep: isComplete ? "result_aggregation" : "continue_execution"
  }
};

// Tax4Us Orchestration Agent - Result Aggregation
const trackingData = $input.first().json;
const coordinationPlan = trackingData.coordination_plan;

console.log("Tax4Us Orchestration Agent - Result Aggregation");

// Aggregate results from all agents
const aggregatedResults = {
  request_id: coordinationPlan.request_id,
  customer_id: coordinationPlan.customer_id,

  // Execution summary
  execution_summary: {
    total_agents: coordinationPlan.execution_plan.total_steps,
    completed_agents: coordinationPlan.execution_plan.progress.completed,
    failed_agents: coordinationPlan.execution_plan.progress.failed,
    total_execution_time: "calculated",
    status: coordinationPlan.status
  },

  // Agent results
  agent_results: {},

  // Combined deliverables
  deliverables: {
    content_ideas: [],
    blog_posts: [],
    social_media_posts: [],
    podcast_episodes: [],
    wordpress_posts: [],
    analytics: {}
  },

  // Customer communication
  customer_updates: coordinationPlan.customer_updates,

  timestamp: new Date().toISOString(),
  status: "results_aggregated"
};

// Process results from each agent
Object.entries(coordinationPlan.execution_plan.results).forEach(([agentId, result]) => {
  aggregatedResults.agent_results[agentId] = result;

  // Extract deliverables based on agent type
  if (agentId === "content_intelligence") {
    if (result.data?.content_ideas) {
      aggregatedResults.deliverables.content_ideas = result.data.content_ideas;
    }
  } else if (agentId === "blog_writing") {
    if (result.data?.blog_post) {
      aggregatedResults.deliverables.blog_posts.push(result.data.blog_post);
    }
  } else if (agentId === "social_media") {
    if (result.data?.facebook_post) {
      aggregatedResults.deliverables.social_media_posts.push({
        platform: "facebook",
        content: result.data.facebook_post
      });
    }
    if (result.data?.linkedin_post) {
      aggregatedResults.deliverables.social_media_posts.push({
        platform: "linkedin",
        content: result.data.linkedin_post
      });
    }
  } else if (agentId === "podcast_agent") {
    if (result.data?.script) {
      aggregatedResults.deliverables.podcast_episodes.push({
        script: result.data.script,
        description: result.data.description,
        artwork_prompt: result.data.artwork_prompt
      });
    }
  }
});

// Calculate execution time
const startTime = new Date(coordinationPlan.customer_updates[0].timestamp);
const endTime = new Date();
const executionTimeMs = endTime - startTime;
const executionTimeMinutes = Math.round(executionTimeMs / 60000);

aggregatedResults.execution_summary.total_execution_time = `${executionTimeMinutes} minutes`;

console.log("✅ Results aggregated successfully!");
console.log(`📊 Total deliverables: ${Object.values(aggregatedResults.deliverables).flat().length}`);
console.log(`⏱️ Execution time: ${executionTimeMinutes} minutes`);

return {
  json: {
    ...aggregatedResults,
    message: "Results aggregated and ready for customer delivery",
    nextStep: "customer_delivery"
  }
};

